# CSVファイルを読み込んで更新
input_file = '/Users/akimotohiroki/insects-host-plant-explorer/public/buprestidae_host.csv'

# Set maximum field size limit
csv.field_size_limit(sys.maxsize)

rows = []
with open(input_file, 'r', encoding='utf-8') as f:
    reader = csv.DictReader(f)
    header = reader.fieldnames
    
    updated_count = 0
    for row in reader:
        # 和名に基づいて更新
        if row.get('和名') in complete_data:
            updates = complete_data[row['和名']]
            updated_count += 1
            
            # 各フィールドを更新
            for key, value in updates.items():
                if key in row:
                    row[key] = value
            
            # 出典を正しく設定
            row["出典"] = "日本産タマムシ大図鑑"
        
        rows.append(row)

# 更新したCSVを元のファイルに上書き
with open(input_file, 'w', encoding='utf-8', newline='') as f:
    writer = csv.DictWriter(f, fieldnames=header)
    writer.writeheader()
    writer.writerows(rows)

print(f"Updated {updated_count} species records in buprestidae_host.csv with complete data including 成虫出現時期")